using System;
using System.Reflection;
using System.Linq;

var asm = Assembly.LoadFrom(Environment.GetCommandLineArgs()[1]);
var assertType = asm.GetTypes().FirstOrDefault(t => t.Name == "Assert");
if (assertType == null) { Console.WriteLine("Assert type not found"); return; }

var methods = assertType.GetMethods(BindingFlags.Public | BindingFlags.Static)
    .Where(m => m.Name == "AreEqual" || m.Name == "AreNotEqual" || m.Name == "AreSame")
    .OrderBy(m => m.Name);

foreach (var m in methods)
{
    var genericArgs = m.IsGenericMethod ? $"<{string.Join(",", m.GetGenericArguments().Select(g => g.Name))}>" : "";
    var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
    Console.WriteLine($"{m.Name}{genericArgs}({parms})");
}
EOF
